import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import copy from "copy-to-clipboard";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function EmployeeManagement() {
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    id: null,
    rolePermissionId: "",
    rmId: "",
    prefix: "Mr",
    name: "",
    email: "",
    phone: "",
    dateOfBirth: "",
    address: "",
    status: "Active",
    totalBalance: "",
    commissionPercentage: "",
    commissionAmount: "",
    orgName: "",
    orgPhone: "",
    orgEmail: "",
    orgAddress: "",
  });

    const [filters, setFilters] = useState({
    employeeSearch: "",
    status: "",
  });
  const [currentPage, setCurrentPage] = useState(1);
  const employeesPerPage = 10;

  const navigate = useNavigate();
  const modalRef = useRef(null);

  /* ================= FETCH ================= */
  function fetchEmployees() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/employees", {
        headers: { Authorization: "Bearer " + token },
      })
      .then((res) => {
        if (res.data.success) {
          setEmployees(res.data.data);
        } else {
          toast.error("Failed to fetch employees");
        }
      })
      .catch(() => toast.error("Error fetching employees"))
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) navigate("/");
    else fetchEmployees();
  }, [navigate]);

  /* ================= INPUT CHANGE ================= */
  function handleInputChange(e) {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  }

  /* ================= ADD / EDIT ================= */
  function openAddModal() {
    setFormData({
      id: null,
      rolePermissionId: "",
      rmId: "",
      prefix: "Mr",
      name: "",
      email: "",
      phone: "",
      dateOfBirth: "",
      address: "",
      status: "Active",
      totalBalance: "",
      commissionPercentage: "",
      commissionAmount: "",
      orgName: "",
      orgPhone: "",
      orgEmail: "",
      orgAddress: "",
    });

    const modalEl = document.getElementById("employeeModal");
    modalRef.current = new Modal(modalEl);
    modalRef.current.show();
  }

  function openEditModal(emp) {
    setFormData(emp);

    const modalEl = document.getElementById("employeeModal");
    modalRef.current = new Modal(modalEl);
    modalRef.current.show();
  }

  function handleSubmit(e) {
    e.preventDefault();
    const token = Cookies.get("adminToken");

    const request = formData.id
      ? axios.put(API_BASE_URL + "/employees/" + formData.id, formData, {
          headers: { Authorization: "Bearer " + token },
        })
      : axios.post(API_BASE_URL + "/employees", formData, {
          headers: { Authorization: "Bearer " + token },
        });

    request
      .then(() => {
        toast.success(
          formData.id
            ? "Employee updated successfully"
            : "Employee created successfully"
        );
        fetchEmployees();
        modalRef.current.hide();
      })
      .catch(() => toast.error("Operation failed"));
  }

  /* ================= FILTER ================= */
  function handleFilterChange(e) {
    const { name, value } = e.target;
    setFilters((prev) => ({ ...prev, [name]: value }));
    setCurrentPage(1);
  }

  /* ================= PAGINATION ================= */
  const indexOfLast = currentPage * employeesPerPage;
  const indexOfFirst = indexOfLast - employeesPerPage;
  const currentEmployees = filteredEmployees.slice(
    indexOfFirst,
    indexOfLast
  );
  const totalPages = Math.ceil(filteredEmployees.length / employeesPerPage);

  function goToNextPage() {
    if (currentPage < totalPages) setCurrentPage((prev) => prev + 1);
  }

  function goToPreviousPage() {
    if (currentPage > 1) setCurrentPage((prev) => prev - 1);
  }

  /* ================= COPY ================= */
  function handleCopy(text, type) {
    if (copy(text)) toast.success(type + " copied");
  }

  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />

      <div className="d-flex justify-content-between mb-3">
        <h4 className="fw-bold">Employee Management</h4>
        <button className="btn btn-primary btn-sm" onClick={openAddModal}>
          + Add Employee
        </button>
      </div>

      {/* SEARCH */}
      <div className="mb-3">
        <input
          type="text"
          className="form-control form-control-sm"
          placeholder="Search (Name, Email, Phone, Role)"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      {/* TABLE */}
      <div className="table-responsive">
        <table className="table table-striped small">
          <thead className="table-dark">
            <tr>
              <th>ID</th>
              <th>Name</th>
              <th>Contact</th>
              <th>Role</th>
              <th>Status</th>
              <th>Balance</th>
              <th>Date</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {currentEmployees.map((emp) => (
              <tr key={emp.id}>
                <td>{emp.id}</td>
                <td>{emp.prefix} {emp.name}</td>
                <td>
                  <i
                    className="fa fa-phone text-success me-2"
                    style={{ cursor: "pointer" }}
                    onClick={() => handleCopy(emp.phone, "Phone")}
                  ></i>
                  <i
                    className="fa fa-envelope text-primary"
                    style={{ cursor: "pointer" }}
                    onClick={() => handleCopy(emp.email, "Email")}
                  ></i>
                </td>
                <td>{emp.role}</td>
                <td>{emp.status}</td>
                <td>{emp.totalBalance}</td>
                <td>
                  <small>
                    Created: {new Date(emp.createdAt).toLocaleDateString()}
                  </small>
                </td>
                <td>
                  <i
                    className="fa fa-pen text-primary me-3"
                    style={{ cursor: "pointer" }}
                    onClick={() => openEditModal(emp)}
                  ></i>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* PAGINATION */}
      <div className="d-flex justify-content-between">
        <div>
          Page {currentPage} of {totalPages}
        </div>
        <div>
          <button
            className="btn btn-sm"
            disabled={currentPage === 1}
            onClick={() => setCurrentPage((p) => p - 1)}
          >
            ◀
          </button>
          <button
            className="btn btn-sm"
            disabled={currentPage === totalPages}
            onClick={() => setCurrentPage((p) => p + 1)}
          >
            ▶
          </button>
        </div>
      </div>

      {/* ADD / EDIT MODAL */}
      <div className="modal fade" id="employeeModal" tabIndex="-1">
        <div className="modal-dialog modal-lg modal-dialog-centered">
          <div className="modal-content">
            <form onSubmit={handleSubmit}>
              <div className="modal-header">
                <h5 className="modal-title">
                  {formData.id ? "Edit Employee" : "Add Employee"}
                </h5>
                <button type="button" className="btn-close" data-bs-dismiss="modal"></button>
              </div>

              <div className="modal-body row g-3">
                <div className="col-md-2">
                  <select
                    name="prefix"
                    className="form-select"
                    value={formData.prefix}
                    onChange={handleChange}
                  >
                    <option>Mr</option>
                    <option>Mrs</option>
                    <option>Miss</option>
                  </select>
                </div>

                <div className="col-md-4">
                  <input
                    type="text"
                    name="name"
                    placeholder="Full Name"
                    className="form-control"
                    value={formData.name}
                    onChange={handleChange}
                    required
                  />
                </div>

                <div className="col-md-3">
                  <input
                    type="email"
                    name="email"
                    placeholder="Email"
                    className="form-control"
                    value={formData.email}
                    onChange={handleChange}
                    required
                  />
                </div>

                <div className="col-md-3">
                  <input
                    type="text"
                    name="phone"
                    placeholder="Phone"
                    className="form-control"
                    value={formData.phone}
                    onChange={handleChange}
                    required
                  />
                </div>

                <div className="col-md-4">
                  <input
                    type="text"
                    name="rolePermissionId"
                    placeholder="Role Permission ID"
                    className="form-control"
                    value={formData.rolePermissionId}
                    onChange={handleChange}
                    required
                  />
                </div>

                <div className="col-md-4">
                  <input
                    type="number"
                    name="commissionPercentage"
                    placeholder="Commission %"
                    className="form-control"
                    value={formData.commissionPercentage}
                    onChange={handleChange}
                  />
                </div>

                <div className="col-md-4">
                  <input
                    type="number"
                    name="totalBalance"
                    placeholder="Total Balance"
                    className="form-control"
                    value={formData.totalBalance}
                    onChange={handleChange}
                  />
                </div>
              </div>

              <div className="modal-footer">
                <button type="submit" className="btn btn-primary">
                  {formData.id ? "Update" : "Create"}
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>

    </div>
  );
}

export default EmployeeManagement;
